import base64
import json

def confirmAuth(headers):
    auth_token = headers.get('AuthToken')
    if not auth_token:
        return None
    try:
        decoded = base64.b64decode(auth_token)
    except (TypeError, ValueError):
        return None
    try:
        data_str = decoded.decode('utf-8')
        token_obj = json.loads(data_str)
    except (json.JSONDecodeError, UnicodeDecodeError):
        return None
    if not token_obj.get('valid', False):
        return None
    return token_obj.get('data')

import os

def read_file_from_dir(filename: str, dir_path: str) -> str:
    if not os.path.isdir(dir_path):
        return ""
    try:
        full_path = os.path.join(dir_path, filename)
        abs_dir = os.path.abspath(dir_path)
        abs_full = os.path.abspath(full_path)
        if not abs_full.startswith(abs_dir):
            return ""
        if not os.path.isfile(abs_full):
            return ""
        with open(abs_full, 'r') as f:
            return f.read()
    except Exception as e:
        return ""

